-- drop "attribute_metrics_summaries_mv" view
DROP VIEW `attribute_metrics_summaries_mv`;
-- create "attribute_metrics_summaries_mv" view
CREATE MATERIALIZED VIEW `attribute_metrics_summaries_mv` TO `attribute_metrics_summaries` AS WITH toUnixTimestamp64Nano(toDateTime64('2026-07-14 00:00:00', 9, 'UTC')) AS attribute_metrics_cutoff_unix_nano, gram_urn = 'claude-code:otel:logs' AS is_claude_otel_row, is_claude_otel_row AND (chat_id != '') AND (toString(attributes.prompt.id) != '') AND ((toString(attributes.event.name) = 'api_request') OR (body = 'claude_code.api_request')) AS is_claude_api_request, is_claude_otel_row AND ((toString(attributes.event.name) = 'tool_result') OR (body = 'claude_code.tool_result')) AS is_claude_tool_result, gram_urn = 'codex:otel:logs' AS is_codex_otel_row, is_codex_otel_row AND (toString(attributes.event.name) = 'codex.sse_event') AND (toString(attributes.event.kind) = 'response.completed') AND ((toString(attributes.input_token_count) != '') OR (toString(attributes.output_token_count) != '')) AS is_codex_api_request, least(greatest(toInt64OrZero(toString(attributes.cached_token_count)), 0), greatest(toInt64OrZero(toString(attributes.input_token_count)), 0)) AS codex_cache_read_tokens, greatest(toInt64OrZero(toString(attributes.input_token_count)), 0) - codex_cache_read_tokens AS codex_input_tokens, startsWith(gram_urn, 'codex:usage') OR startsWith(gram_urn, 'cursor:usage') OR startsWith(gram_urn, 'claude_chat:usage') OR startsWith(gram_urn, 'claude_chat:cost') AS is_agent_usage_row, is_claude_api_request OR is_codex_api_request OR is_agent_usage_row AS is_usage_row, (toString(attributes.gram.hook.source) NOT IN ('', 'claude-code')) AND (toString(attributes.gram.tool.name) != '') AND (toString(attributes.gram.tool.name) NOT IN ('claude-code', 'codex', 'cursor')) AND (toString(attributes.gram.hook.event) IN ('PostToolUse', 'PostToolUseFailure')) AS is_agent_tool_call, is_claude_tool_result OR is_agent_tool_call AS is_counted_tool_call, multiIf(toString(attributes.tool_use_id) != '', toString(attributes.tool_use_id), toString(attributes.gen_ai.tool.call.id) != '', toString(attributes.gen_ai.tool.call.id), toString(id)) AS tool_call_dedup_id SELECT gram_project_id, toStartOfHour(fromUnixTimestamp64Nano(time_unix_nano)) AS time_bucket, toString(attributes.user.attributes.department_name) AS department_name, toString(attributes.user.attributes.job_title) AS job_title, toString(attributes.user.attributes.employee_type) AS employee_type, toString(attributes.user.attributes.division_name) AS division_name, toString(attributes.user.attributes.cost_center_name) AS cost_center_name, user_email AS user_email, multiIf(is_claude_api_request AND (toString(attributes.model) != ''), toString(attributes.model), is_claude_api_request AND (toString(attributes.gen_ai.request.model) != ''), toString(attributes.gen_ai.request.model), toString(attributes.gen_ai.response.model)) AS model, hook_source, arraySort(JSONExtract(ifNull(toJSONString(attributes.user.roles), '[]'), 'Array(String)')) AS roles, arraySort(JSONExtract(ifNull(toJSONString(attributes.user.groups), '[]'), 'Array(String)')) AS groups, uniqExactIfState(toString(attributes.gen_ai.conversation.id), (toString(attributes.gen_ai.conversation.id) != '') AND is_usage_row) AS total_chats, sumIfState(multiIf(is_claude_api_request, toInt64OrZero(toString(attributes.input_tokens)), is_codex_api_request, codex_input_tokens, toInt64OrZero(toString(attributes.gen_ai.usage.input_tokens))), is_usage_row) AS total_input_tokens, sumIfState(multiIf(is_claude_api_request, toInt64OrZero(toString(attributes.output_tokens)), is_codex_api_request, toInt64OrZero(toString(attributes.output_token_count)), toInt64OrZero(toString(attributes.gen_ai.usage.output_tokens))), is_usage_row) AS total_output_tokens, sumIfState(multiIf(is_claude_api_request, (toInt64OrZero(toString(attributes.input_tokens)) + toInt64OrZero(toString(attributes.output_tokens))) + toInt64OrZero(toString(attributes.cache_creation_tokens)), is_codex_api_request, codex_input_tokens + toInt64OrZero(toString(attributes.output_token_count)), (toInt64OrZero(toString(attributes.gen_ai.usage.input_tokens)) + toInt64OrZero(toString(attributes.gen_ai.usage.output_tokens))) + toInt64OrZero(toString(attributes.gen_ai.usage.cache_creation.input_tokens))), is_usage_row) AS total_tokens, sumIfState(multiIf(is_claude_api_request, toInt64OrZero(toString(attributes.cache_read_tokens)), is_codex_api_request, codex_cache_read_tokens, toInt64OrZero(toString(attributes.gen_ai.usage.cache_read.input_tokens))), is_usage_row) AS cache_read_input_tokens, sumIfState(if(is_claude_api_request, toInt64OrZero(toString(attributes.cache_creation_tokens)), toInt64OrZero(toString(attributes.gen_ai.usage.cache_creation.input_tokens))), is_usage_row) AS cache_creation_input_tokens, sumIfState(if(is_claude_api_request, multiIf(toString(attributes.cost_usd) != '', toFloat64OrZero(toString(attributes.cost_usd)), toString(attributes.cost_usd_micros) != '', toFloat64OrZero(toString(attributes.cost_usd_micros)) / 1000000, 0), toFloat64OrZero(toString(attributes.gen_ai.usage.cost))), is_usage_row) AS total_cost, countIfState(is_counted_tool_call) AS total_tool_calls, uniqExactIfState(tool_call_dedup_id, is_counted_tool_call) AS unique_tool_calls, account_type, provider, billing_mode, if(is_claude_api_request, toString(attributes.query_source), '') AS query_source, if(is_claude_api_request, toString(attributes.skill.name), '') AS skill_name, if(is_claude_api_request, toString(attributes.agent.name), '') AS agent_name, if(is_claude_api_request, toString(attributes.mcp_server.name), '') AS mcp_server_name, if(is_claude_api_request, toString(attributes.mcp_tool.name), '') AS mcp_tool_name, toUInt8(2) AS generation, toUInt8(1) AS is_active, toString(attributes.gram.hook.hostname) AS hook_hostname FROM telemetry_logs WHERE (time_unix_nano >= attribute_metrics_cutoff_unix_nano) AND (is_claude_api_request OR is_claude_tool_result OR is_codex_api_request OR is_agent_usage_row OR is_agent_tool_call) GROUP BY gram_project_id, time_bucket, department_name, job_title, employee_type, division_name, cost_center_name, user_email, model, hook_source, roles, groups, account_type, provider, billing_mode, query_source, skill_name, agent_name, mcp_server_name, mcp_tool_name, hook_hostname;
-- drop "chat_session_summaries_mv" view
DROP VIEW `chat_session_summaries_mv`;
-- create "chat_session_summaries_mv" view
CREATE MATERIALIZED VIEW `chat_session_summaries_mv` TO `chat_session_summaries` AS WITH toUnixTimestamp64Nano(toDateTime64('2026-07-21 22:00:00', 9, 'UTC')) AS chat_session_cutoff_unix_nano, gram_urn = 'claude-code:otel:logs' AS is_claude_otel_row, is_claude_otel_row AND (chat_id != '') AND (toString(attributes.prompt.id) != '') AND ((toString(attributes.event.name) = 'api_request') OR (body = 'claude_code.api_request')) AS is_claude_api_request, is_claude_otel_row AND ((toString(attributes.event.name) = 'tool_result') OR (body = 'claude_code.tool_result')) AS is_claude_tool_result, gram_urn = 'codex:otel:logs' AS is_codex_otel_row, is_codex_otel_row AND (toString(attributes.event.name) = 'codex.sse_event') AND (toString(attributes.event.kind) = 'response.completed') AND ((toString(attributes.input_token_count) != '') OR (toString(attributes.output_token_count) != '')) AS is_codex_api_request, least(greatest(toInt64OrZero(toString(attributes.cached_token_count)), 0), greatest(toInt64OrZero(toString(attributes.input_token_count)), 0)) AS codex_cache_read_tokens, greatest(toInt64OrZero(toString(attributes.input_token_count)), 0) - codex_cache_read_tokens AS codex_input_tokens, startsWith(gram_urn, 'codex:usage') OR startsWith(gram_urn, 'cursor:usage') OR startsWith(gram_urn, 'claude_chat:usage') OR startsWith(gram_urn, 'claude_chat:cost') AS is_agent_usage_row, (hook_source NOT IN ('', 'claude-code')) AND (toString(attributes.gram.tool.name) != '') AND (toString(attributes.gram.tool.name) NOT IN ('claude-code', 'codex', 'cursor')) AND (toString(attributes.gram.hook.event) IN ('PostToolUse', 'PostToolUseFailure')) AS is_agent_tool_call, is_claude_tool_result OR is_agent_tool_call AS is_counted_tool_call, is_claude_api_request OR is_codex_api_request OR is_agent_usage_row AS is_usage_row, (is_claude_tool_result AND (toString(attributes.success) = 'false')) OR (is_agent_tool_call AND ((toString(attributes.gram.hook.event) = 'PostToolUseFailure') OR (toInt32OrZero(toString(attributes.http.response.status_code)) >= 400))) AS is_failed_tool_call, multiIf(toString(attributes.tool_use_id) != '', toString(attributes.tool_use_id), toString(attributes.gen_ai.tool.call.id) != '', toString(attributes.gen_ai.tool.call.id), toString(id)) AS tool_call_dedup_id, multiIf(is_claude_api_request, toString(attributes.prompt.id), is_codex_api_request, toString(id), toString(attributes.gen_ai.response.id)) AS session_message_id, multiIf(is_claude_api_request AND (toString(attributes.model) != ''), toString(attributes.model), is_claude_api_request AND (toString(attributes.gen_ai.request.model) != ''), toString(attributes.gen_ai.request.model), toString(attributes.gen_ai.response.model)) AS effective_model SELECT gram_project_id, toStartOfHour(fromUnixTimestamp64Nano(time_unix_nano, 'UTC')) AS time_bucket, chat_id, max(user_email) AS session_user_email, max(hook_source) AS session_hook_source, argMaxIfState(effective_model, time_unix_nano, effective_model != '') AS session_model, min(time_unix_nano) AS start_time_unix_nano, max(time_unix_nano) AS end_time_unix_nano, uniqExactIfState(session_message_id, session_message_id != '') AS message_count, uniqExactIfState(tool_call_dedup_id, is_counted_tool_call) AS tool_call_count, countIf(is_failed_tool_call) AS failed_tool_call_count, sumIf(multiIf(is_claude_api_request, toInt64OrZero(toString(attributes.input_tokens)), is_codex_api_request, codex_input_tokens, toInt64OrZero(toString(attributes.gen_ai.usage.input_tokens))), is_usage_row) AS total_input_tokens, sumIf(multiIf(is_claude_api_request, toInt64OrZero(toString(attributes.output_tokens)), is_codex_api_request, toInt64OrZero(toString(attributes.output_token_count)), toInt64OrZero(toString(attributes.gen_ai.usage.output_tokens))), is_usage_row) AS total_output_tokens, sumIf(multiIf(is_claude_api_request, (toInt64OrZero(toString(attributes.input_tokens)) + toInt64OrZero(toString(attributes.output_tokens))) + toInt64OrZero(toString(attributes.cache_creation_tokens)), is_codex_api_request, codex_input_tokens + toInt64OrZero(toString(attributes.output_token_count)), (toInt64OrZero(toString(attributes.gen_ai.usage.input_tokens)) + toInt64OrZero(toString(attributes.gen_ai.usage.output_tokens))) + toInt64OrZero(toString(attributes.gen_ai.usage.cache_creation.input_tokens))), is_usage_row) AS total_tokens, sumIf(multiIf(is_claude_api_request, toInt64OrZero(toString(attributes.cache_read_tokens)), is_codex_api_request, codex_cache_read_tokens, toInt64OrZero(toString(attributes.gen_ai.usage.cache_read.input_tokens))), is_usage_row) AS cache_read_input_tokens, sumIf(if(is_claude_api_request, toInt64OrZero(toString(attributes.cache_creation_tokens)), toInt64OrZero(toString(attributes.gen_ai.usage.cache_creation.input_tokens))), is_usage_row) AS cache_creation_input_tokens, sumIf(if(is_claude_api_request, multiIf(toString(attributes.cost_usd) != '', toFloat64OrZero(toString(attributes.cost_usd)), toString(attributes.cost_usd_micros) != '', toFloat64OrZero(toString(attributes.cost_usd_micros)) / 1000000, 0), toFloat64OrZero(toString(attributes.gen_ai.usage.cost))), is_usage_row) AS total_cost, groupUniqArray(toString(attributes.user.attributes.department_name)) AS department_names, groupUniqArray(toString(attributes.user.attributes.job_title)) AS job_titles, groupUniqArray(toString(attributes.user.attributes.employee_type)) AS employee_types, groupUniqArray(toString(attributes.user.attributes.division_name)) AS division_names, groupUniqArray(toString(attributes.user.attributes.cost_center_name)) AS cost_center_names, groupUniqArray(if(user_email != '', user_email, toString(attributes.gram.hook.hostname))) AS emails, groupUniqArray(toString(attributes.gram.hook.hostname)) AS hostnames, groupUniqArray(effective_model) AS models, groupUniqArray(hook_source) AS hook_sources, groupUniqArray(account_type) AS account_types, groupUniqArray(provider) AS providers, groupUniqArray(billing_mode) AS billing_modes, groupUniqArrayArray(arraySort(JSONExtract(ifNull(toJSONString(attributes.user.roles), '[]'), 'Array(String)'))) AS roles, groupUniqArrayArray(arraySort(JSONExtract(ifNull(toJSONString(attributes.user.groups), '[]'), 'Array(String)'))) AS groups, groupUniqArrayIf((toString(attributes.query_source), toString(attributes.skill.name), toString(attributes.agent.name), toString(attributes.mcp_server.name), toString(attributes.mcp_tool.name)), is_claude_api_request) AS attribution_tuples FROM telemetry_logs WHERE (time_unix_nano >= chat_session_cutoff_unix_nano) AND (chat_id != '') AND (is_claude_api_request OR is_claude_tool_result OR is_codex_api_request OR is_agent_usage_row OR is_agent_tool_call) GROUP BY gram_project_id, time_bucket, chat_id;
